export async function loginHandler(req: Request): Promise<Response> {
  const body = await req.json();
  const parsed = LoginSchema.safeParse(body);
  if (!parsed.success) return Response.json({ error: parsed.error }, { status: 400 });
  const user = await findUserByEmail(parsed.data.email);
  if (!user) return Response.json({ error: 'invalid credentials' }, { status: 401 });
  const ok = await verifyPassword(parsed.data.password, user.passwordHash);
  if (!ok) return Response.json({ error: 'invalid credentials' }, { status: 401 });
  const session = await createSession(user.id);
  return Response.json({ token: session.token });
}

const LoginSchema = z.object({
  email: z.string().email(),
  password: z.string().min(8),
});

export async function logoutHandler(req: Request): Promise<Response> {
  const token = extractBearerToken(req);
  if (!token) return Response.json({ error: 'missing token' }, { status: 400 });
  await revokeSession(token);
  return Response.json({ ok: true });
}

export async function createSession(userId: string): Promise<Session> {
  const token = crypto.randomUUID();
  const expiresAt = new Date(Date.now() + SESSION_TTL_MS);
  await db.insert(sessions).values({ token, userId, expiresAt });
  return { token, userId, expiresAt };
}

export async function revokeSession(token: string): Promise<void> {
  await db.delete(sessions).where(eq(sessions.token, token));
}

export async function verifyPassword(plain: string, hash: string): Promise<boolean> {
  return bcrypt.compare(plain, hash);
}

export async function createInvoice(userId: string, items: InvoiceItem[]): Promise<Invoice> {
  const totalCents = items.reduce((sum, i) => sum + i.priceCents * i.quantity, 0);
  const invoice = await db.insert(invoices).values({ userId, totalCents, status: 'open' }).returning();
  return invoice[0];
}

export async function stripeWebhookHandler(req: Request): Promise<Response> {
  const sig = req.headers.get('stripe-signature');
  if (!sig) return Response.json({ error: 'missing signature' }, { status: 400 });
  const event = stripe.webhooks.constructEvent(await req.text(), sig, env.STRIPE_WEBHOOK_SECRET);
  if (event.type === 'invoice.paid') {
    await markInvoicePaid(event.data.object.id);
  }
  return Response.json({ ok: true });
}

export async function retryWithBackoff<T>(fn: () => Promise<T>, opts: { max: number; baseMs: number }): Promise<T> {
  let lastErr: unknown;
  for (let attempt = 1; attempt <= opts.max; attempt++) {
    try { return await fn(); } catch (err) { lastErr = err; }
    await new Promise((r) => setTimeout(r, opts.baseMs * 2 ** (attempt - 1)));
  }
  throw lastErr instanceof Error ? lastErr : new Error('retry exhausted');
}

import pino from 'pino';

export const logger = pino({
  level: process.env.LOG_LEVEL ?? 'info',
  redact: ['req.headers.authorization', 'token', 'password'],
});

export const env = {
  DATABASE_URL: process.env.DATABASE_URL!,
  STRIPE_SECRET: process.env.STRIPE_SECRET!,
  STRIPE_WEBHOOK_SECRET: process.env.STRIPE_WEBHOOK_SECRET!,
  SESSION_TTL_MS: Number(process.env.SESSION_TTL_MS ?? 7 * 24 * 60 * 60 * 1000),
};
